/* =============================================================================
   Admin display name (DB)
   - Pulls from admin table using session admin_id (adjust table/column if needed)
   ============================================================================= */
if (!function_exists('htccc_admin_display_name_from_db')) {
    function htccc_admin_display_name_from_db(mysqli $db_connection): string {
        if (session_status() !== PHP_SESSION_ACTIVE) {
            @session_start();
        }

        // CHANGE THIS if your admin table name is different
        $adminTable = 'admin_table';

        // Admin id from session (adjust if your system uses different key)
        $adminId = 0;
        if (!empty($_SESSION['admin_id'])) {
            $adminId = (int)$_SESSION['admin_id'];
        } elseif (!empty($_SESSION['user_id'])) {
            $adminId = (int)$_SESSION['user_id'];
        }

        // If cannot resolve ID, fallback to any session name if exists
        if ($adminId <= 0) {
            if (!empty($_SESSION['admin_lastname']) || !empty($_SESSION['admin_firstname'])) {
                $ln = trim((string)($_SESSION['admin_lastname'] ?? ''));
                $fn = trim((string)($_SESSION['admin_firstname'] ?? ''));
                $mn = trim((string)($_SESSION['admin_middlename'] ?? ''));
                $out = trim($ln . ', ' . $fn . ' ' . $mn);
                $out = trim(preg_replace('/\s+/', ' ', $out));
                return $out !== '' ? $out : 'Admin';
            }
            return 'Admin';
        }

        // Title-case helper (optional)
        $titleCase = function ($s) {
            $s = trim((string)$s);
            if ($s === '') return '';
            return preg_replace_callback(
                '/\b(\p{L})(\p{L}*)/u',
                fn($m) => mb_strtoupper($m[1]).mb_strtolower($m[2]),
                $s
            );
        };

        // Query admin table
        $sql = "SELECT admin_lastname, admin_firstname, admin_middlename
                FROM {$adminTable}
                WHERE admin_id = ?
                LIMIT 1";

        if ($stmt = mysqli_prepare($db_connection, $sql)) {
            mysqli_stmt_bind_param($stmt, "i", $adminId);
            mysqli_stmt_execute($stmt);
            $res = mysqli_stmt_get_result($stmt);

            if ($row = mysqli_fetch_assoc($res)) {
                $ln = $titleCase($row['admin_lastname'] ?? '');
                $fn = $titleCase($row['admin_firstname'] ?? '');
                $mn = $titleCase($row['admin_middlename'] ?? '');

                mysqli_stmt_close($stmt);

                // Format: Lastname, Firstname Middlename
                $name = '';
                if ($ln !== '' && $fn !== '') {
                    $name = $ln . ', ' . $fn;
                } elseif ($ln !== '') {
                    $name = $ln;
                } elseif ($fn !== '') {
                    $name = $fn;
                }

                if ($mn !== '') {
                    $name .= ($name !== '' ? ' ' : '') . $mn;
                }

                return $name !== '' ? $name : ('Admin #' . $adminId);
            }

            mysqli_stmt_close($stmt);
        }

        return 'Admin #' . $adminId;
    }
}

// ===== DATA LOAD (Done funeral services) =====
$rows = [];
if (isset($db_connection) && $db_connection instanceof mysqli) {
    $sql = "
        SELECT
          funeral_id,
          individual_lastname,
          individual_firstname,
          individual_middlename,
          individual_ext AS individual_extension,
          deceased_lastname,
          deceased_firstname,
          deceased_middlename,
          deceased_birthdate,
          home_address,
          service_date,
          appointment_date
        FROM service_funeral
        WHERE service_status = 'Done'
        ORDER BY COALESCE(service_date, appointment_date) DESC, funeral_id DESC
    ";
    if ($res = $db_connection->query($sql)) {
        while ($r = $res->fetch_assoc()) {

            // Service date
            if (!empty($r['service_date'])) {
                $ts = strtotime($r['service_date']);
                $r['_service_date_raw']  = date('Y-m-d', $ts);
                $r['_service_date_disp'] = date('M d, Y', $ts);
            } else {
                $r['_service_date_raw']  = '';
                $r['_service_date_disp'] = '';
            }

            // Appointment date/time
            if (!empty($r['appointment_date'])) {
                $ts = strtotime($r['appointment_date']);
                $r['_appointment_raw']  = date('Y-m-d H:i:s', $ts);
                $r['_appointment_date'] = date('M d, Y', $ts);
                $r['_appointment_time'] = date('h:i A', $ts);
            } else {
                $r['_appointment_raw']  = '';
                $r['_appointment_date'] = '';
                $r['_appointment_time'] = '';
            }

            // Deceased birthdate
            if (!empty($r['deceased_birthdate'])) {
                $ts = strtotime($r['deceased_birthdate']);
                $r['_deceased_birth_raw']  = date('Y-m-d', $ts);
                $r['_deceased_birth_disp'] = date('M d, Y', $ts);
            } else {
                $r['_deceased_birth_raw']  = '';
                $r['_deceased_birth_disp'] = '';
            }

            $rows[] = $r;
        }
        $res->free();
    }
}

