      border-radius:999px;
      width:30px;
      height:30px;
      display:flex;
      align-items:center;
      justify-content:center;
      font-size:18px;
      cursor:pointer;
      transition:.15s ease background,.15s ease color,.15s ease transform;
    }
    .close-btn:hover{
      background:#020617;
      transform:scale(1.02);
    }

    .modal .body{
      padding:18px 22px 20px;
      overflow:auto;
      scrollbar-width:thin;
      scrollbar-color:#CBD5F5 transparent;
    }
    .modal .body::-webkit-scrollbar{width:8px}
    .modal .body::-webkit-scrollbar-thumb{
      background:#CBD5F5;
      border-radius:999px;
    }

    .modal-section{
      background:#FFFFFF;
      border-radius:18px;
      padding:14px 16px 10px;
      border:1px solid #E0E7FF;
      margin-bottom:14px;
      box-shadow:0 8px 18px rgba(148,163,184,.25);
    }
    .modal-section-title{
      margin:0 0 10px;
      font-size:13px;
      font-weight:700;
      color:#111827;
      display:flex;
      align-items:center;
      gap:8px;
    }
    .modal-section-title::before{
      content:"";
      display:inline-block;
      width:3px;
      height:15px;
      border-radius:999px;
      background:linear-gradient(180deg,#4F46E5,#22C1C3);
    }

    .kv{
      display:grid;
      grid-template-columns:210px 1fr;
      gap:8px 18px;
      font-size:13px;
      padding:7px 0;
      border-top:1px dashed #E5E7EB;
    }
    .kv:first-of-type{border-top:none;padding-top:0}
    .kv-label{
      color:#6B7280;
      font-weight:600;
    }
    .kv-value{
      color:#111827;
      word-break:break-word;
    }
    .kv-value .muted{
      color:#9CA3AF;
      font-style:italic;
    }

    /* ===== IMAGE VIEWER (kept for future doc images) ===== */
    .imgbox{
      position:fixed;
      inset:0;
      display:none;
      align-items:center;
      justify-content:center;
      background:rgba(0,0,0,.6);
      z-index:100000;
      padding:16px;
    }
    .imgbox[aria-hidden="false"]{ display:flex; }
    .imgbox-inner{
      position:relative;
      max-width:min(1000px, 96vw);
      max-height:90vh;
      background:#0f1720;
      border:1px solid rgba(255,255,255,.18);
      border-radius:14px;
      box-shadow:0 30px 80px rgba(0,0,0,.5);
      overflow:hidden;
    }
    .imgbox-inner img{
      display:block;
      max-width:100%;
      max-height:90vh;
      height:auto;
      width:auto;
    }
    .imgbox-close{
      position:absolute;
      top:8px; right:8px;
      border:0; background:#1f2a38; color:#fff;
      border-radius:10px; padding:6px 10px;
      cursor:pointer;
      z-index:2;
