<!-- ===== JS: Search • Sort • Modal + PDF Download ===== -->
<script>
(function(){
  const $  = (s,root=document)=>root.querySelector(s);
  const $$ = (s,root=document)=>Array.from(root.querySelectorAll(s));
  const tableBody   = $('#tableBody');
  const searchInput = $('#searchInput');
  const sortRequester = $('#sortRequester');
  const sortDeceased  = $('#sortDeceased');
  const sortDate    = $('#sortDate');
  const applySort   = $('#applySort');
  const downloadPdf = $('#downloadPdf');

  // Modal elements
  const backdrop = $('#viewModalBackdrop');
  const modalBody = $('#modalBody');
  const closeBtn = $('#modalCloseBtn');

  // Image viewer elements
  const imgBox = document.getElementById('imgBox');
  const imgBoxImg = document.getElementById('imgBoxImg');
  const imgBoxCloseBtn = document.getElementById('imgBoxCloseBtn');

  const esc = s => (s ?? '').toString().replace(/[&<>"']/g, c=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));

  function textOrDash(v){
    const val = (v || '').toString().trim();
    return val ? esc(val) : '<span class="muted">—</span>';
  }

  function openModal(tr){
    const html = `
      <section class="modal-section">
        <h4 class="modal-section-title">Appointment Information</h4>
        <div class="kv">
          <div class="kv-label">Service Date</div>
          <div class="kv-value">${
            textOrDash(tr.dataset.service_date
              ? new Date(tr.dataset.service_date).toLocaleDateString(undefined,{year:'numeric',month:'short',day:'2-digit'})
              : ''
            )
          }</div>
        </div>
        <div class="kv">
          <div class="kv-label">Appointment Date</div>
          <div class="kv-value">${textOrDash(tr.dataset.appointmentDate)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">Appointment Time</div>
          <div class="kv-value">${textOrDash(tr.dataset.appointmentTime)}</div>
        </div>
      </section>

      <section class="modal-section">
        <h4 class="modal-section-title">Requester Information</h4>
        <div class="kv">
          <div class="kv-label">Last Name</div>
          <div class="kv-value">${textOrDash(tr.dataset.individual_lastname)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">First Name</div>
          <div class="kv-value">${textOrDash(tr.dataset.individual_firstname)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">Middle Name</div>
          <div class="kv-value">${textOrDash(tr.dataset.individual_middlename)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">Extension</div>
          <div class="kv-value">${textOrDash(tr.dataset.individual_extension)}</div>
        </div>
      </section>

      <section class="modal-section">
        <h4 class="modal-section-title">Deceased Information</h4>
        <div class="kv">
          <div class="kv-label">Last Name</div>
          <div class="kv-value">${textOrDash(tr.dataset.deceased_lastname)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">First Name</div>
          <div class="kv-value">${textOrDash(tr.dataset.deceased_firstname)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">Middle Name</div>
          <div class="kv-value">${textOrDash(tr.dataset.deceased_middlename)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">Birthdate</div>
          <div class="kv-value">${textOrDash(tr.dataset.deceased_birthdate)}</div>
        </div>
        <div class="kv">
          <div class="kv-label">Home Address</div>
          <div class="kv-value">${textOrDash(tr.dataset.home_address)}</div>
        </div>
      </section>
    `;

    modalBody.innerHTML = html;
    backdrop.classList.add('open');
    backdrop.setAttribute('aria-hidden','false');
  }

  function closeModal(){
    backdrop.classList.remove('open');
    backdrop.setAttribute('aria-hidden','true');
  }

  backdrop.addEventListener('click', e=>{ if(e.target === backdrop) closeModal(); });
  closeBtn.addEventListener('click', closeModal);
  document.addEventListener('keydown', e=>{ if(e.key === 'Escape') closeModal(); });

  function wireViewButtons(){
    $$('.btn-view', tableBody).forEach(btn=>{
      btn.onclick = () => {
        const tr = btn.closest('tr');
        tr.dataset.appointmentDate = tr.dataset.appointment_date || tr.dataset.appointment_date;
        tr.dataset.appointmentTime = tr.dataset.appointment_time || tr.dataset.appointment_time;
        openModal(tr);
      };
    });
  }
  wireViewButtons();

  function applyFilters(){
    const q = (searchInput.value || '').toLowerCase().trim();
    const rows = $$('#tableBody tr');

    rows.forEach(r=>{
      if (r.classList.contains('empty-row')) return;
      r.style.display = '';
      if(q){
        const hay = [
          r.dataset.service_date,
          r.dataset.appointment_raw,
          r.dataset.individual_lastname, r.dataset.individual_firstname, r.dataset.individual_middlename, r.dataset.individual_extension,
          r.dataset.deceased_lastname, r.dataset.deceased_firstname, r.dataset.deceased_middlename,
          r.dataset.home_address
        ].join(' ').toLowerCase();
        if(!hay.includes(q)) r.style.display = 'none';
      }
    });

    const dateVal   = sortDate.value;
    const reqVal    = sortRequester.value;
    const decVal    = sortDeceased.value;

    const visible = rows.filter(r=>!r.classList.contains('empty-row') && r.style.display!=='none');

    visible.sort((a,b)=>{
      if (dateVal === 'date_desc') {
        const da = Date.parse(a.dataset.service_date || '1970-01-01');
        const db = Date.parse(b.dataset.service_date || '1970-01-01');
        if (db !== da) return db - da;
      } else if (reqVal === 'requester') {
        const la = (a.dataset.individual_lastname || '').toLowerCase();
        const lb = (b.dataset.individual_lastname || '').toLowerCase();
        if (la !== lb) return la < lb ? -1 : 1;
      } else if (decVal === 'deceased') {
        const la = (a.dataset.deceased_lastname || '').toLowerCase();
        const lb = (b.dataset.deceased_lastname || '').toLowerCase();
        if (la !== lb) return la < lb ? -1 : 1;
      }

      const da2 = Date.parse(a.dataset.service_date || '1970-01-01');
      const db2 = Date.parse(b.dataset.service_date || '1970-01-01');
      if (db2 !== da2) return db2 - da2;

      const la2 = (a.dataset.individual_lastname || '').toLowerCase();
      const lb2 = (b.dataset.individual_lastname || '').toLowerCase();
      if (la2 !== lb2) return la2 < lb2 ? -1 : 1;

      return 0;
    });

    visible.forEach(r=>tableBody.appendChild(r));
    rows.filter(r=>r.style.display==='none').forEach(r=>tableBody.appendChild(r));

    wireViewButtons();
  }

  searchInput.addEventListener('input', applyFilters);
  applySort.addEventListener('click', applyFilters);

  // PDF DOWNLOAD
  if (downloadPdf) {
    downloadPdf.addEventListener('click', () => {
      window.location = 'done-service-funeral.php?download=funeral_pdf';
    });
  }

  // IMAGE VIEWER (kept)
  function openImgBox(src){
    if (!imgBox || !imgBoxImg) return;
    imgBoxImg.src = src;
    imgBox.setAttribute('aria-hidden','false');
  }
  function closeImgBox(){
    if (!imgBox || !imgBoxImg) return;
    imgBoxImg.src = '';
    imgBox.setAttribute('aria-hidden','true');
  }

  document.addEventListener('click', (e) => {
    const btn = e.target.closest('.view-image[data-img]');
    if (!btn) return;
    e.preventDefault();
    const src = btn.getAttribute('data-img');
    if (src) openImgBox(src);
  });

  if (imgBox) {
    imgBox.addEventListener('click', (e) => {
      if (e.target === imgBox) closeImgBox();
    });
  }
  if (imgBoxCloseBtn) imgBoxCloseBtn.addEventListener('click', closeImgBox);

  applyFilters();
})();
</script>

</body>
</html>
